  1→import { useInfiniteQuery, useQuery } from '@tanstack/react-query';
  2→import '../ProfilePage/myprofile.css';
  3→import './visitProfile.css';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getFollowsData, getUserData, getUserJournals, getUserByUsername } from '../../../API/Api';
  6→import { Fragment, useEffect, useRef } from 'react';
  7→import { Outlet, useLocation, useNavigate, useParams } from 'react-router-dom';
  8→import Sidebar from '../SideBar/Sidebar';
  9→import { MoonLoader } from 'react-spinners';
 10→import { useFollowMutation } from '../../utils/useMutation';
 11→import debounce from '../../../helpers/debounce';
 12→import VerifiedBadge from '../Badge/VerifiedBadge';
 13→import formatCounts from '../../../helpers/fomatCounts';
 14→import MobileNavlink from '../mobileNavLink/MobileNavLink';
 15→import MobileSidebarLink from '../MobileSidebarLink/MobileSidebarLink';
 16→import { useState } from 'react';
 17→import WriteJournalButton from '../WriteJournalButton/WriteJournalButton';
 18→import Editor from '../HomePage/Editor/Editor';
 19→import Loader from '../loadingComponent/BgLoader';
 20→import useProfileSeo from '../../seo/useProfileSeo';
 21→import { createProfileSidebarLinks } from '../ProfilePage/constants/profileSidebarLinks';
 22→import ShareMenu from '../ShareMenu/ShareMenu';
 23→import { getProfileShareUrl } from '../../utils/getShareUrl';
 24→
 25→const Visitprofile = () =>{
 26→    const location = useLocation();
 27→    const stateData = location.state;
 28→    const { username: urlUsername } = useParams();
 29→    const queryUserId = new URLSearchParams(location.search).get('userId');
 30→    const isUsernameRoute = !!urlUsername;
 31→
 32→    // Fetch user by username if on /@username route
 33→    const { data: usernameData, isLoading: isLoadingByUsername } = useQuery({
 34→        queryKey: ['userByUsername', urlUsername],
 35→        queryFn: () => getUserByUsername(urlUsername),
 36→        enabled: isUsernameRoute,
 37→        staleTime: 1000 * 60 * 5,
 38→        refetchOnWindowFocus: false,
 39→    });
 40→
 41→    // Resolve visitedUserId from either username lookup, state, or query param
 42→    const visitedUserId = isUsernameRoute
 43→        ? usernameData?.userData?.[0]?.id
 44→        : (stateData?.userId || queryUserId);
 45→
 46→    const resolvedUsername = isUsernameRoute
 47→        ? urlUsername
 48→        : usernameData?.userData?.[0]?.username;
 49→
 50→    const {session, user, notifCount, loading} = useAuth();
 51→
 52→    const [showSidebar, setShowSidebar]= useState(false)
 53→    const [opendRichTextEditor, setOpenRichTextEditor] = useState(false);
 54→    const [showShareMenu, setShowShareMenu] = useState(false);
 55→
 56→    const buttonRef = useRef();
 57→
 58→    const navigate = useNavigate();
 59→    const visitedProfileNavState = { userId: visitedUserId };
 60→    const visibleProfileSections = [{id: 'stats'}, {id: 'bio'}, {id: 'joined_date'}];
 61→
 62→    // Use @username paths when available, fall back to legacy /visitProfile paths
 63→    const profileUsername = resolvedUsername || usernameData?.userData?.[0]?.username;
 64→    const useNewUrls = !!profileUsername;
 65→    const tablists = useNewUrls
 66→        ? [
 67→            {label: 'Writings', path: `/u/${profileUsername}`, action: () => navigate(`/u/${profileUsername}`, {state: visitedProfileNavState})},
 68→            {label: 'Media', path: `/u/${profileUsername}/media`, action: () => navigate(`/u/${profileUsername}/media`, {state: visitedProfileNavState})},
 69→            {label: 'Collections', path: `/u/${profileUsername}/collections`, action: () => navigate(`/u/${profileUsername}/collections`, {state: visitedProfileNavState})},
 70→            {label: 'Opinions', path: `/u/${profileUsername}/opinions`, action: () => navigate(`/u/${profileUsername}/opinions`, {state: visitedProfileNavState})}
 71→        ]
 72→        : [
 73→            {label: 'Writings', path: '/visitProfile', action: () => navigate(`/visitProfile?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})},
 74→            {label: 'Media', path: '/visitProfile/media', action: () => navigate(`/visitProfile/media?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})},
 75→            {label: 'Collections', path: '/visitProfile/visitedCollections', action: () => navigate(`/visitProfile/visitedCollections?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})},
 76→            {label: 'Opinions', path:'/visitProfile/visitedOpinions', action: () => navigate(`/visitProfile/visitedOpinions?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})}
 77→        ]
 78→
 79→     const navigatePath = (path) => {
 80→        return navigate(path)
 81→    }
 82→
 83→    const handleMouseMove = (isFollowing) =>{
 84→        if(buttonRef.current){
 85→            if(isFollowing){
 86→                buttonRef.current.innerText = 'Unfollow'
 87→            } else {
 88→                return
 89→            }
 90→        }
 91→    }
 92→
 93→    //open rich text editor
 94→    const handleClickRichtextEditor = () =>{
 95→        setOpenRichTextEditor(true);
 96→    }
 97→    //close rich text editor
 98→    const handleCloseRichtextEditor = () =>{
 99→        setOpenRichTextEditor(false);
100→    }
101→
102→    // open sidebar through boolean function
103→    const openSidebar = () =>{
104→        setShowSidebar(true)
105→    }
106→
107→    // close sidebar through boolean function
108→    const closeSidebar = () =>{
109→        setShowSidebar(false)
110→    }
111→
112→    const handleMouseLeave = (isFollowing) =>{
113→        if(buttonRef.current){
114→            if(isFollowing){
115→                buttonRef.current.innerText = 'Following'
116→            } else {
117→                return
118→            }
119→        }
120→    }
121→
122→    const mutationFollow = useFollowMutation(session);
123→    const hadnleClickFollow = (e, followingId, followerId,) =>{
124→        mutationFollow.mutate({followingId, followerId})
125→    }
126→    const debounceClickFollow = debounce(hadnleClickFollow, 0)
127→
128→    const links = createProfileSidebarLinks({
129→        location,
130→        navigatePath,
131→        navigate,
132→        notifCount,
133→        setShowEditor: setOpenRichTextEditor,
134→    });
135→
136→    
137→    const {data, isLoading} = useQuery({
138→        queryKey: ['visitedProfile', visitedUserId],
139→        queryFn:({queryKey}) => getUserData(queryKey[1]),
140→        enabled: !!visitedUserId && !isUsernameRoute,
141→        refetchOnWindowFocus: false
142→    })
143→
144→    // Use username-fetched data when on /@username route, otherwise use userId-fetched data
145→    const userData = isUsernameRoute
146→        ? usernameData?.userData?.[0]
147→        : data?.userData?.[0]
148→
149→    useProfileSeo(userData, profileUsername);
150→    const getProfileSectionSize = () => 'md';
151→
152→    const{data: followsData, isLoading: isLoadingFollowsData} = useQuery({
153→        queryKey: ['followsData', user?.userData?.[0].id, visitedUserId],
154→        queryFn: ({queryKey}) => getFollowsData(queryKey[1], queryKey[2]),
155→        staleTime: 1000 * 60 * 60,
156→        cacheTime: 1000 * 60 * 60,
157→        enabled: !!user?.userData?.[0].id && !!visitedUserId,
158→        refetchOnWindowFocus: false
159→    })
160→
161→
162→    useEffect(() =>{
163→        console.log(data)
164→    }, [data])
165→
166→    useEffect(() => {
167→        if(!session && !loading){
168→            return navigate('/login')
169→            //check if the user has user metadata on the users table database if not then show a UI that let them input there data and save to database
170→        }
171→    
172→    },[session, loading])
173→
174→    if(isLoading || isLoadingByUsername){
175→        return(
176→            <Loader/>
177→        )
178→    }
179→    return(
180→        <>{opendRichTextEditor &&(
181→            <Editor onClose={handleCloseRichtextEditor}/>
182→        )}
183→        
184→        <div className='profile-parent-container'>
185→            {userData?.background && (
186→                <div className="blurred-img-bg" style={userData?.background}/>
187→            )}
188→
189→            <div className="side-bar-holder-container">
190→                <Sidebar links={links}/> {/*passing the setShowEditor to this component to be used as a state setter inside this component*/}
191→            </div>
192→
193→            <div style={{color: userData?.profile_font_color}} className="profile-center-bar-container">
194→                {userData && (
195→
196→                    <div style={userData?.background} className='visit-profile-hero-section'>
197→
198→                        <div className='visited-profile-top-row'>
199→                            <div className={`profile-avatar-ring ${userData?.badge === 'legend' ? 'badge-ring-legend' : userData?.badge === 'og' ? 'badge-ring-og' : ''}`}>
200→                                <img className='visited-profile-image' src={userData?.image_url || '/assets/profile.jpg'} alt={`${userData?.name || "User"} profile picture`} />
201→                            </div>
202→                        </div>
203→
204→                        <div className='visited-profile-name-container'>
205→                            <div className='visited-profile-name-row'>
206→                                <p className='visited-profile-name'>{userData?.name}</p>
207→                                <VerifiedBadge badge={userData?.badge} size={22} />
208→                                {userData?.badge && (
209→                                    <span className={`badge-pill ${userData.badge === 'legend' ? 'badge-pill-legend' : 'badge-pill-og'}`}>
210→                                        {userData.badge === 'legend' ? 'Legend' : 'OG'}
211→                                    </span>
212→                                )}
213→                            </div>
214→                            {(profileUsername || userData?.username) && (
215→                                <p className="visited-profile-handle">@{profileUsername || userData.username}</p>
216→                            )}
217→                        </div>
218→
219→                        <div className='visited-profile-layout-sections'>
220→                            {visibleProfileSections.map((section) => {
221→                                const sectionSize = getProfileSectionSize(section.id);
222→
223→                                if(section.id === 'stats'){
224→                                    return (
225→                                        <Fragment key={section.id}>
226→                                            <div className={`visited-profile-stats-container profile-section-size-${sectionSize}`}>
227→                                                <div className='visited-profile-stat-item'>
228→                                                    <span className='visited-stat-number'>{formatCounts(followsData?.followersCount)}</span>
229→                                                    <span className='visited-stat-label'>Followers</span>
230→                                                </div>
231→                                                <div className='visited-profile-stat-item'>
232→                                                    <span className='visited-stat-number'>{formatCounts(followsData?.followingsCount)}</span>
233→                                                    <span className='visited-stat-label'>Following</span>
234→                                                </div>
235→                                            </div>
236→                                        </Fragment>
237→                                    );
238→                                }
239→
240→                                if(section.id === 'bio'){
241→                                    return (
242→                                        <Fragment key={section.id}>
243→                                            <div className={`visited-profile-bio-container profile-section-size-${sectionSize}`}>
244→                                                <p style={{margin: 0, padding: 0}}>{userData?.bio}</p>
245→                                            </div>
246→                                        </Fragment>
247→                                    );
248→                                }
249→
250→                                if(section.id === 'joined_date'){
251→                                    return (
252→                                        <Fragment key={section.id}>
253→                                            <div className={`visited-profile-joined-date profile-section-size-${sectionSize}`}>
254→                                                <p className='visited-profile-date-joined'>{new Date(userData?.created_at).toLocaleDateString('en-US', {
255→                                                    month: 'long',
256→                                                    day: '2-digit',
257→                                                    year: 'numeric'
258→                                                })}</p>
259→                                            </div>
260→                                        </Fragment>
261→                                    );
262→                                }
263→
264→                                return null;
265→                            })}
266→                        </div>
267→
268→                        <div className='visited-profile-actions-row'>
269→                            <div onMouseMove={() => handleMouseMove(followsData?.isFollowing)} onMouseLeave={() => handleMouseLeave(followsData?.isFollowing)} className='visited-profile-follow-button-container'>
270→                                <button onClick={(e) => debounceClickFollow(e, visitedUserId, user?.userData?.[0].id)} ref={buttonRef} className={followsData?.isFollowing ? 'unfollow-visited-profile-bttn' : 'follow-visited-profile-bttn'}>
271→                                    {followsData?.isFollowing ? 'Following' : 'Follow'}
272→                                </button>
273→                            </div>
274→                            {(profileUsername || userData?.username) && (
275→                                <div className="visit-profile-share-btn" style={{ position: 'relative' }} onClick={(e) => { e.stopPropagation(); setShowShareMenu((v) => !v); }}>
276→                                    <svg xmlns="http://www.w3.org/2000/svg" height="18px" viewBox="0 0 24 24" width="18px" fill="currentColor">
277→                                        <path d="M18 16.08c-.76 0-1.44.3-1.96.77L8.91 12.7c.05-.23.09-.46.09-.7s-.04-.47-.09-.7l7.05-4.11c.54.5 1.25.81 2.04.81 1.66 0 3-1.34 3-3s-1.34-3-3-3-3 1.34-3 3c0 .24.04.47.09.7L8.04 9.81C7.5 9.31 6.79 9 6 9c-1.66 0-3 1.34-3 3s1.34 3 3 3c.79 0 1.5-.31 2.04-.81l7.12 4.16c-.05.21-.08.43-.08.65 0 1.61 1.31 2.92 2.92 2.92 1.61 0 2.92-1.31 2.92-2.92s-1.31-2.92-2.92-2.92z"/>
278→                                    </svg>
279→                                    {showShareMenu && (
280→                                        <ShareMenu
281→                                            url={getProfileShareUrl(profileUsername || userData.username)}
282→                                            title={`${userData.name || profileUsername || userData.username}'s Profile`}
283→                                            onClose={() => setShowShareMenu(false)}
284→                                        />
285→                                    )}
286→                                </div>
287→                            )}
288→                        </div>
289→
290→                    </div>
291→
292→                    )
293→                }
294→
295→                <div className='my-profile-tablist'>
296→                    {tablists.map((tab, index) => (
297→                         <div key={index} onClick={() => tab.action()} className='tab-container'>
298→                            {tab.label}
299→                            <div className={location.pathname === tab.path ? 'tab-indicator' : ''}/>
300→                        </div>
301→                    ))}
302→                   
303→                </div>
304→
305→                <Outlet/>
306→
307→            </div>
308→            
309→            <div className="profile-sidebar-right-holder-container" />
310→
311→            {showSidebar && (
312→                <MobileSidebarLink onclose={closeSidebar}/>
313→            )}
314→            
315→            {<MobileNavlink clickOpenSidebar={openSidebar}/>}
316→            <WriteJournalButton onOpen={handleClickRichtextEditor}/>
317→        </div>
318→        </>
319→
320→    )
321→}
322→export default Visitprofile;
