 41→const StoryEditor = lazy(() => import('./components/Stories/StoryEditor/StoryEditor.jsx'));
 42→const StoryChapterManager = lazy(() => import('./components/Stories/StoryChapterManager/StoryChapterManager.jsx'));
 43→const ChapterEditor = lazy(() => import('./components/Stories/ChapterEditor/ChapterEditor.jsx'));
 44→const StoryBrowser = lazy(() => import('./components/Stories/StoryBrowser/StoryBrowser.jsx'));
 45→const StoryLibrary = lazy(() => import('./components/Stories/StoryLibrary/StoryLibrary.jsx'));
 46→const StoryDetail = lazy(() => import('./components/Stories/StoryDetail/StoryDetail.jsx'));
 47→const ChapterReader = lazy(() => import('./components/Stories/ChapterReader/ChapterReader.jsx'));
 48→
 49→const AppAuthModal = () => {
 50→  const {showAuthModal, closeAuthModal} = useAuth();
 51→  return <AuthModal isOpen={showAuthModal} onClose={closeAuthModal}/>;
 52→}
 53→
 54→const AppSplash = () => {
 55→  const { loading } = useAuth();
 56→  return <Loader isLoading={loading} />;
 57→}
 58→
 59→const App = () => {
 60→
 61→  const theme = {
 62→    paragraph: 'editor-paragraph',
 63→    heading: {
 64→      h1: 'editor-heading-h1',
 65→      h2: 'editor-heading-h2',
 66→      h3: 'editor-heading-h3',
 67→    },
 68→    quote: 'editor-quote',
 69→    text: {
 70→      bold: 'editor-text-bold',
 71→      italic: 'editor-text-italic',
 72→      underline: 'editor-text-underline',
 73→    }
 74→  }
 75→  
 76→  const initaConfig = {
 77→  namespace: "MyLexicalEditor",
 78→  theme,
 79→  //register nodes
 80→  nodes: [ImageNode, HeadingNode, QuoteNode],
 81→  onError(error){
 82→  throw error;
 83→  },
 84→}
 85→
 86→  return (
 87→    <>
 88→    <LexicalComposer initialConfig={initaConfig}>
 89→      <BrowserRouter>
