 99→              <Route path='media' element={<ProfileMediaSection/>} />
100→              <Route path='myOpinions' element={<MyOpinions/>}/>         
101→            </Route>
102→
103→            <Route path='/visitProfile' element={<Visitprofile/>}>
104→              <Route index element={<VisitedProfilePostCards/>}/>
105→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
106→              <Route path='visitedCollections' element={<CollectionViewer/>}/>
107→              <Route path='visitedOpinions' element={<VisitedProfileOpinions/>}/>
108→            </Route>
109→
110→            <Route path='/u/:username' element={<Visitprofile/>}>
111→              <Route index element={<VisitedProfilePostCards/>}/>
112→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
113→              <Route path='collections' element={<CollectionViewer/>}/>
114→              <Route path='opinions' element={<VisitedProfileOpinions/>}/>
115→            </Route>
116→
117→            <Route path='/home' element={<HomePage/>}>
118→              <Route index element={<PostCards/>}/>
119→              <Route path='explore' element={<ExplorePage/>}/>
120→              <Route path='gallery' element={<GalleryPage/>}/>
121→              <Route path='freedom-wall' element={<FreedomWallPage/>}/>
122→              <Route path='contentViewer' element={<ContentView/>}/>
123→              <Route path='post/:journalId' element={<ContentView/>}/>
124→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
125→              <Route path='bookmark' element={<Bookmarks/>}/>
126→              <Route path='userCollections' element={<ViewUserCollection/>}/>
127→              <Route path='opinions'element={<OpinionsPage/>}/>
128→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
129→
130→              <Route path='collections' element={<Collections/>}/>
131→              <Route path='collectionCards' element={<CollectionJournals/>}/>
132→              <Route path='settings' element={<SettingsPage/>}/>
133→
134→              {/* Stories routes */}
135→              <Route path='stories' element={<StoryBrowser/>}/>
136→              <Route path='stories/library' element={<StoryLibrary/>}/>
137→              <Route path='stories/dashboard' element={<StoryDashboard/>}/>
138→              <Route path='stories/new' element={<StoryEditor/>}/>
139→              <Route path='stories/:storyId' element={<StoryDetail/>}/>
140→              <Route path='stories/:storyId/edit' element={<StoryEditor/>}/>
141→              <Route path='stories/:storyId/manage' element={<StoryChapterManager/>}/>
142→              <Route path='stories/:storyId/chapter/:chapterId' element={<ChapterReader/>}/>
143→              <Route path='stories/:storyId/chapter/:chapterId/edit' element={<ChapterEditor/>}/>
144→
145→              {/* route for nested notifications */}
146→              <Route path='notifications' element={<Notifications/>}>
147→                <Route index element={<NotificationCards/>}/>
148→                <Route path='unreadNotification' element={<UnreadNotification/>}/>
149→              </Route>  
150→            </Route>   
151→
152→            <Route path='/universe' element={<Universe/>}/>
153→
154→            <Route path='/login' element={<LoginPage/>}/>
155→            <Route path='/signUp' element={<SignUp/>}/>
156→          </Routes>
157→        </Suspense>
158→      </BrowserRouter>
159→    </LexicalComposer>
160→    </>
161→  )
162→}
163→
164→export default App
